import Header from '@/components/layout/header'
import SportsGrid from '@/components/sports/Sportsgrid'
import MatchesCarousel from '@/components/home/MatchesCarousel'
import LiveSchedule from '@/components/home/LiveSchedule'

export const metadata = {
  title: 'ReedStreams - Live Sports Streaming',
  description: 'Watch live sports matches including Football, Cricket, MMA, and more.',
}

const STREAMED_API_BASE = process.env.NEXT_PUBLIC_STREAMED_API_BASE_URL || 'https://streamed.pk/api'

// Fetch logic
async function getAllMatches() {
  try {
    const res = await fetch(`${STREAMED_API_BASE}/matches/all-today`, { cache: 'no-store' })
    if (!res.ok) return []
    const allMatches = await res.json()
    
    // Filter for TODAY (UTC Logic)
    const now = new Date()
    const todayUTC = now.toISOString().slice(0, 10)
    
    return allMatches.filter((match: any) => {
        const matchDateUTC = new Date(match.date).toISOString().slice(0, 10)
        return matchDateUTC === todayUTC && match.sources?.length > 0
    })
  } catch (error) {
    console.error("Fetch Error:", error)
    return []
  }
}

export default async function Home() {
  const allMatches = await getAllMatches()

  // Filter Categories
  const nflMatches = allMatches.filter((m: any) => m.category === 'americanfootball')
  const basketballMatches = allMatches.filter((m: any) => m.category === 'basketball')
  const soccerMatches = allMatches.filter((m: any) => m.category === 'football')
  const hockeyMatches = allMatches.filter((m: any) => m.category === 'hockey')
  const cricketMatches = allMatches.filter((m: any) => m.category === 'cricket')
  const f1Matches = allMatches.filter((m: any) => m.category === 'motorsport' || m.category === 'motorsports')

  return (
    <main className="min-h-screen bg-[#0f1115]">
      <Header />
      <SportsGrid />
      
      {/* 3. Detailed List View (Optional/Legacy) */}
      {/* <LiveSchedule schedule={...} />  <-- If you still want the vertical list, you can adapt it, but Carousel is cleaner */}
      
    </main>
  )
}